options.onRender:
(() => {
  const root = htmlNode.querySelector('#root');
  if (!root) return;
  if (!data?.series?.length) { root.innerHTML=`<div style='padding:20px;color:#666;text-align:center'>Aguardando dados...</div>`; return; }
  const parse = (series) => {
    const fields = {};
    series?.fields?.forEach(f => { fields[f.name] = { values: f.values?.toArray ? f.values.toArray() : (f.values||[]) }; });
    const r = {};
    Object.keys(fields).forEach(k => r[k] = fields[k].values[0]);
    return r;
  };
  const host = parse(data.series[0]);
  const fp = data.series[1] ? parse(data.series[1]) : {};
  const statusColor = s => s==='online'?'#00C851':s==='stale'?'#ffbb33':'#ff4444';
  const statusLabel = s => s==='online'?'ONLINE':s==='stale'?'INSTÁVEL':'OFFLINE';
  const statusAnim = s => s==='online'?'pulse-green':'pulse-red';
  const fmtCpu = v => { const n=Number(v); if(isNaN(n)||v==null) return 'N/A'; const c=n>=95?'#ff4444':n>=80?'#ffbb33':'#00C851'; return `<span style='color:${c};font-size:24px;font-weight:800'>${n.toFixed(1)}%</span>`; };
  const fmtRam = v => { const n=Number(v); if(isNaN(n)||v==null) return 'N/A'; const c=n>=95?'#ff4444':n>=85?'#ffbb33':'#00C851'; return `<span style='color:${c};font-size:24px;font-weight:800'>${n.toFixed(1)}%</span>`; };
  const fmtTime = v => { try{return new Date(v).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'});}catch{return v||'N/A';} };
  const fpShort = v => v ? v.substring(0,16)+'...' : 'N/A';
  root.innerHTML = `
  <style>
    .wrap{padding:16px;animation:fadeIn .4s ease}
    .cards{display:grid;grid-template-columns:auto 1fr 1fr 1fr 1fr;gap:12px;align-items:stretch}
    .card-host{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:14px;padding:16px 24px;display:flex;align-items:center;gap:16px}
    .status-dot{width:16px;height:16px;border-radius:50%;flex-shrink:0}
    .host-name{font-size:20px;font-weight:800;color:#e9eefc}
    .host-sub{font-size:12px;color:rgba(220,230,255,.5);margin-top:4px}
    .status-badge{display:inline-block;margin-top:8px;padding:4px 12px;border-radius:20px;font-size:11px;font-weight:700}
    .card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:14px;padding:16px 20px}
    .card-lbl{font-size:11px;color:rgba(220,230,255,.5);font-weight:600;text-transform:uppercase;letter-spacing:.5px;margin-bottom:8px}
    .card-val{font-size:24px;font-weight:800;color:#e9eefc;line-height:1}
    .card-sub{font-size:11px;color:rgba(220,230,255,.4);margin-top:6px}
    .dns-ok{color:#00C851;font-weight:700}.dns-off{color:#ff4444;font-weight:700}
    .fp{font-size:11px;font-family:monospace;color:rgba(220,230,255,.5);margin-top:4px}
  </style>
  <div class='wrap'>
    <div class='cards'>
      <div class='card-host'>
        <div class='status-dot' style='background:${statusColor(host.agent_status)};animation:${statusAnim(host.agent_status)} 2s infinite'></div>
        <div>
          <div class='host-name'>${host.hostname||'N/A'}</div>
          <div class='host-sub'>${host.display_name||''}${host.location?' · '+host.location:''}</div>
          <span class='status-badge' style='background:${statusColor(host.agent_status)}22;color:${statusColor(host.agent_status)}'>${statusLabel(host.agent_status)}</span>
        </div>
      </div>
      <div class='card'>
        <div class='card-lbl'>CPU</div>
        <div class='card-val'>${fmtCpu(host.cpu_percent)}</div>
        <div class='card-sub'>Último heartbeat</div>
      </div>
      <div class='card'>
        <div class='card-lbl'>RAM</div>
        <div class='card-val'>${fmtRam(host.ram_percent)}</div>
        <div class='card-sub'>Último heartbeat</div>
      </div>
      <div class='card'>
        <div class='card-lbl'>Serviço DNS</div>
        <div class='card-val' style='font-size:16px'>${host.dns_service_name?`<span class='${host.dns_service_active?'dns-ok':'dns-off'}'>${host.dns_service_name} ${host.dns_service_active?'✓':'✗'}</span>`:'<span style="color:#666">N/A</span>'}</div>
        <div class='card-sub'>Esperado: ${host.expected_dns_service||'qualquer'}</div>
      </div>
      <div class='card'>
        <div class='card-lbl'>Último contato</div>
        <div class='card-val' style='font-size:16px;color:#e9eefc'>${fmtTime(host.last_seen)}</div>
        <div class='fp' title='${fp.fingerprint||''}'>${fpShort(fp.fingerprint)}</div>
      </div>
    </div>
  </div>`;
})();

(() => {
  const root = htmlNode.querySelector('#root');
  if (!root) return;
  const fields = {};
  data.series?.forEach(s => s.fields?.forEach(f => { if (!fields[f.name]) fields[f.name] = { values: f.values?.toArray ? f.values.toArray() : (f.values||[]) }; }));
  const rowCount = Math.max(...Object.values(fields).map(f=>f.values.length),0);
  const rows = [];
  for (let i=0;i<rowCount;i++) { const r={}; Object.keys(fields).forEach(k=>r[k]=fields[k].values[i]); rows.push(r); }
  if (rows.length===0) { root.innerHTML=`<div style='padding:40px;color:#666;text-align:center'>Sem dados no período</div>`; return; }
  const W=root.clientWidth||600, H=200, PL=40, PR=16, PT=16, PB=32;
  const vals = rows.map(r=>Number(r.cpu)||0);
  const maxV = Math.max(...vals,100);
  const toX = i => PL + (i/(rows.length-1||1))*(W-PL-PR);
  const toY = v => PT + (1-v/maxV)*(H-PT-PB);
  const pts = rows.map((r,i)=>`${toX(i).toFixed(1)},${toY(Number(r.cpu)||0).toFixed(1)}`).join(' ');
  const area = `M${toX(0).toFixed(1)},${toY(0).toFixed(1)} ${rows.map((r,i)=>`L${toX(i).toFixed(1)},${toY(Number(r.cpu)||0).toFixed(1)}`).join(' ')} L${toX(rows.length-1).toFixed(1)},${toY(0).toFixed(1)} Z`;
  const yLines = [0,25,50,75,100];
  const fmtTime = v => { try{return new Date(v).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});}catch{return '';} };
  const lastVal = vals[vals.length-1];
  const avgVal = (vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1);
  const maxVal = Math.max(...vals).toFixed(1);
  const lineColor = v => v>=95?'#ff4444':v>=80?'#ffbb33':'#667eea';
  root.innerHTML = `
  <style>
    .wrap{padding:12px 16px;height:100%;display:flex;flex-direction:column;gap:8px}
    .stats{display:flex;gap:16px}
    .stat{font-size:11px;color:rgba(220,230,255,.5)}.stat span{font-weight:700;color:#e9eefc}
  </style>
  <div class='wrap'>
    <div class='stats'>
      <div class='stat'>Atual: <span style='color:${lineColor(lastVal)}'>${lastVal.toFixed(1)}%</span></div>
      <div class='stat'>Média: <span>${avgVal}%</span></div>
      <div class='stat'>Máx: <span style='color:${lineColor(Number(maxVal))}'>${maxVal}%</span></div>
    </div>
    <svg width='100%' height='${H}' viewBox='0 0 ${W} ${H}' preserveAspectRatio='none'>
      <defs>
        <linearGradient id='cpuGrad' x1='0' y1='0' x2='0' y2='1'>
          <stop offset='0%' stop-color='${lineColor(lastVal)}' stop-opacity='0.3'/>
          <stop offset='100%' stop-color='${lineColor(lastVal)}' stop-opacity='0.02'/>
        </linearGradient>
      </defs>
      ${yLines.map(v=>`
        <line x1='${PL}' y1='${toY(v).toFixed(1)}' x2='${W-PR}' y2='${toY(v).toFixed(1)}' stroke='rgba(255,255,255,.06)' stroke-width='1'/>
        <text x='${PL-4}' y='${toY(v).toFixed(1)+4}' fill='rgba(220,230,255,.35)' font-size='9' text-anchor='end'>${v}%</text>
      `).join('')}
      <rect x='${toX(rows.length-1)*0.75}' y='${PT}' width='${(W-PL-PR)*0.25}' fill='rgba(255,68,68,.06)' height='${H-PT-PB}' rx='2'/>
      <path d='${area}' fill='url(#cpuGrad)'/>
      <polyline points='${pts}' fill='none' stroke='${lineColor(lastVal)}' stroke-width='2' stroke-linejoin='round'/>
      ${rows.filter((_,i)=>i%(Math.ceil(rows.length/6))||i===rows.length-1).map((r,_,arr)=>{
        const idx=rows.indexOf(r);
        return `<text x='${toX(idx).toFixed(1)}' y='${H-4}' fill='rgba(220,230,255,.35)' font-size='9' text-anchor='middle'>${fmtTime(r.ts)}</text>`;
      }).join('')}
    </svg>
  </div>`;
})();

