(() => {
  const root = htmlNode.querySelector('#root');
  if (!root) return;
  const fields = {};
  data.series?.forEach(s => s.fields?.forEach(f => { if (!fields[f.name]) fields[f.name] = { values: f.values?.toArray ? f.values.toArray() : (f.values||[]) }; }));
  const rowCount = Math.max(...Object.values(fields).map(f=>f.values.length),0);
  const rows = [];
  for (let i=0;i<rowCount;i++) { const r={}; Object.keys(fields).forEach(k=>r[k]=fields[k].values[i]); rows.push(r); }
  if (rows.length===0) { root.innerHTML=`<div style='padding:40px;color:#666;text-align:center'>Sem dados no período</div>`; return; }
  // Agrupar por domínio
  const domains = [...new Set(rows.map(r=>r.domain))];
  const colors = ['#667eea','#00b4d8','#00C851','#ffbb33','#ff6b6b','#a855f7'];
  const W=root.clientWidth||600, H=180, PL=40, PR=16, PT=16, PB=32;
  const allMs = rows.filter(r=>r.success).map(r=>Number(r.latency_ms)||0);
  const maxV = Math.max(...allMs, 200);
  const minTs = Math.min(...rows.map(r=>new Date(r.ts).getTime()));
  const maxTs = Math.max(...rows.map(r=>new Date(r.ts).getTime()));
  const toX = t => PL + ((new Date(t).getTime()-minTs)/(maxTs-minTs||1))*(W-PL-PR);
  const toY = v => PT + (1-Math.min(v,maxV)/maxV)*(H-PT-PB);
  const fmtTime = v => { try{return new Date(v).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});}catch{return '';} };
  root.innerHTML = `
  <style>
    .wrap{padding:12px 16px;display:flex;flex-direction:column;gap:8px}
    .legend{display:flex;gap:12px;flex-wrap:wrap}
    .leg{display:flex;align-items:center;gap:4px;font-size:11px;color:rgba(220,230,255,.6)}
    .leg-dot{width:10px;height:3px;border-radius:2px}
    .fails{display:flex;gap:8px;flex-wrap:wrap;margin-top:4px}
    .fail-badge{padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700;background:rgba(255,68,68,.15);color:#ff6b6b}
  </style>
  <div class='wrap'>
    <div class='legend'>
      ${domains.map((d,i)=>`<div class='leg'><div class='leg-dot' style='background:${colors[i%colors.length]};height:2px;width:12px'></div>${d}</div>`).join('')}
    </div>
    <svg width='100%' height='${H}' viewBox='0 0 ${W} ${H}' preserveAspectRatio='none'>
      ${[0,100,200,500,1000].filter(v=>v<=maxV).map(v=>`
        <line x1='${PL}' y1='${toY(v).toFixed(1)}' x2='${W-PR}' y2='${toY(v).toFixed(1)}' stroke='rgba(255,255,255,.06)' stroke-width='1'/>
        <text x='${PL-4}' y='${toY(v).toFixed(1)+4}' fill='rgba(220,230,255,.35)' font-size='9' text-anchor='end'>${v}ms</text>
      `).join('')}
      ${domains.map((d,di)=>{
        const dRows = rows.filter(r=>r.domain===d && r.success);
        if (dRows.length<2) return '';
        const pts = dRows.map(r=>`${toX(r.ts).toFixed(1)},${toY(Number(r.latency_ms)||0).toFixed(1)}`).join(' ');
        return `<polyline points='${pts}' fill='none' stroke='${colors[di%colors.length]}' stroke-width='2' stroke-linejoin='round' opacity='.85'/>`;
      }).join('')}
      ${rows.filter(r=>!r.success).map(r=>`
        <circle cx='${toX(r.ts).toFixed(1)}' cy='${toY(0).toFixed(1)}' r='4' fill='#ff4444' opacity='.8'>
          <title>${r.domain}: ${r.error_code||'ERRO'}</title>
        </circle>
      `).join('')}
      ${[0,.25,.5,.75,1].map(p=>{
        const t = minTs + p*(maxTs-minTs);
        const x = PL + p*(W-PL-PR);
        return `<text x='${x.toFixed(1)}' y='${H-4}' fill='rgba(220,230,255,.35)' font-size='9' text-anchor='middle'>${fmtTime(new Date(t))}</text>`;
      }).join('')}
    </svg>
    ${rows.filter(r=>!r.success).length>0?`<div class='fails'>${[...new Set(rows.filter(r=>!r.success).map(r=>r.error_code||'ERRO'))].map(e=>`<span class='fail-badge'>${rows.filter(r=>r.error_code===e).length}× ${e}</span>`).join('')}</div>`:''}
  </div>`;
})();

